import{_ as i,o as s,c as e,a2 as l}from"./chunks/framework.LN3EJxkW.js";const k=JSON.parse('{"title":"Embedding、向量、点积与余弦相似度","description":"","frontmatter":{"type":"ai-note","stage":"beginner","topic":"embeddings-vector-similarity","verified":"2026-07-17T00:00:00.000Z","tags":["ai","embeddings","vectors","dot-product","cosine-similarity"]},"headers":[],"relativePath":"04-ai/notes/foundations/embeddings-vector-similarity.md","filePath":"04-ai/notes/foundations/embeddings-vector-similarity.md","lastUpdated":1784249568000}'),t={name:"04-ai/notes/foundations/embeddings-vector-similarity.md"};function n(d,a,r,o,h,p){return s(),e("div",null,[...a[0]||(a[0]=[l(`<h1 id="embedding、向量、点积与余弦相似度" tabindex="-1">Embedding、向量、点积与余弦相似度 <a class="header-anchor" href="#embedding、向量、点积与余弦相似度" aria-label="Permalink to &quot;Embedding、向量、点积与余弦相似度&quot;">​</a></h1><h2 id="_1-概念、用途与工程边界" tabindex="-1">1. 概念、用途与工程边界 <a class="header-anchor" href="#_1-概念、用途与工程边界" aria-label="Permalink to &quot;1. 概念、用途与工程边界&quot;">​</a></h2><h3 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h3><p>Embedding 是把离散对象映射为固定维度数值向量的表示。向量的各维通常不能单独用人工语义解释，但整体几何关系可用于相似度、检索、聚类和分类。点积是对应维度乘积之和。余弦相似度是点积除以两个向量长度，衡量方向接近程度。</p><h3 id="为什么需要" tabindex="-1">为什么需要 <a class="header-anchor" href="#为什么需要" aria-label="Permalink to &quot;为什么需要&quot;">​</a></h3><p>文本不能直接用传统数值索引比较语义。Embedding 将查询和文档放到同一向量空间，允许近邻检索。理解相似度才能正确选择索引度量、阈值和归一化方式。</p><h3 id="核心特性" tabindex="-1">核心特性 <a class="header-anchor" href="#核心特性" aria-label="Permalink to &quot;核心特性&quot;">​</a></h3><p>对于向量 <code>a</code>、<code>b</code>：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dot(a,b) = Σ aᵢbᵢ</span></span>
<span class="line"><span>cos(a,b) = dot(a,b) / (||a|| ||b||)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><ul><li>点积同时受方向和长度影响。</li><li>余弦相似度忽略整体长度，值通常位于 -1 到 1；具体 Embedding 分布不保证覆盖整个区间。</li><li>若向量已做 L2 归一化，点积等于余弦相似度。</li><li>不同模型、维度或版本生成的向量通常不能直接混用。</li><li>相似表示统计相关，不保证事实相同、逻辑蕴含或满足权限。</li></ul><h3 id="工程使用" tabindex="-1">工程使用 <a class="header-anchor" href="#工程使用" aria-label="Permalink to &quot;工程使用&quot;">​</a></h3><ol><li>明确检索单位：标题、段落、页面还是对象字段。</li><li>使用同一 Embedding 模型和预处理生成文档与查询向量。</li><li>在向量数据库中配置与模型建议一致的距离度量。</li><li>取 Top-K 后再做元数据权限过滤或在检索阶段强制过滤。</li><li>用标注问题集评估 Recall@K，而不是凭几次搜索调整阈值。</li><li>模型升级时新建索引或完整重算，并记录版本。</li></ol><h3 id="常见错误与边界" tabindex="-1">常见错误与边界 <a class="header-anchor" href="#常见错误与边界" aria-label="Permalink to &quot;常见错误与边界&quot;">​</a></h3><ul><li>混用不同 Embedding 模型的向量。</li><li>将余弦距离和余弦相似度的排序方向弄反；数据库定义可能不同。</li><li>只检索向量相似内容，不结合关键词、实体、日期和权限过滤。</li><li>把高相似度当作答案正确或文档支持结论。</li><li>在向量写入后丢失原文、来源和版本，无法引用或删除。</li></ul><h3 id="延伸机制" tabindex="-1">延伸机制 <a class="header-anchor" href="#延伸机制" aria-label="Permalink to &quot;延伸机制&quot;">​</a></h3><p>近似最近邻索引用召回率换取速度和内存。Hybrid Search 将关键词与向量信号结合；Reranker 对较小候选集做更精细排序。两者都需要真实查询集评估。</p><h2 id="从对象到检索结果" tabindex="-1">从对象到检索结果 <a class="header-anchor" href="#从对象到检索结果" aria-label="Permalink to &quot;从对象到检索结果&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;文档与元数据&quot;] --&gt; B[&quot;切分和规范化&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[&quot;同一 Embedding 模型&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[&quot;向量与模型版本&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E[&quot;查询&quot;] --&gt; C</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; F[&quot;权限过滤与近邻检索&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; G[&quot;可选 Rerank&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H[&quot;原文、来源与分数&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>权限过滤必须在受控系统中执行。若数据库只能检索后过滤，应扩大候选集并评估漏召回，但不能把无权限文档发送给生成模型。</p><h2 id="数学量与数据库术语" tabindex="-1">数学量与数据库术语 <a class="header-anchor" href="#数学量与数据库术语" aria-label="Permalink to &quot;数学量与数据库术语&quot;">​</a></h2><table tabindex="0"><thead><tr><th>名称</th><th>定义</th><th>排序方向</th><th>边界</th></tr></thead><tbody><tr><td>点积</td><td><code>Σaᵢbᵢ</code></td><td>通常越大越相似</td><td>受向量长度影响</td></tr><tr><td>余弦相似度</td><td><code>dot/(norm(a)norm(b))</code></td><td>越大越相似</td><td>零向量时未定义</td></tr><tr><td>余弦距离</td><td>常见定义为 <code>1-cos</code></td><td>越小越近</td><td>数据库可能采用不同命名</td></tr><tr><td>Top-K</td><td>返回分数最优的 K 个候选</td><td>由度量决定</td><td>K 不是质量保证</td></tr><tr><td>Recall@K</td><td>相关文档在前 K 个中被召回的比例</td><td>越大越好</td><td>需要标注相关集合</td></tr></tbody></table><h2 id="可计算示例" tabindex="-1">可计算示例 <a class="header-anchor" href="#可计算示例" aria-label="Permalink to &quot;可计算示例&quot;">​</a></h2><p>令 <code>a=[1,0]</code>、<code>b=[2,0]</code>、<code>c=[1,1]</code>。<code>dot(a,b)=2</code>，<code>cos(a,b)=1</code>；<code>dot(a,c)=1</code>，<code>cos(a,c)=1/√2≈0.707</code>。<code>b</code> 与 <code>a</code> 方向完全相同，但长度不同；这说明点积和余弦不能在未确认归一化与索引定义时互换。</p><h2 id="验证与排错" tabindex="-1">验证与排错 <a class="header-anchor" href="#验证与排错" aria-label="Permalink to &quot;验证与排错&quot;">​</a></h2><ol><li>断言查询和索引记录具有相同模型 ID、维度和预处理版本。</li><li>用手算向量验证数据库的分数名称与排序方向。</li><li>在标注查询集上计算 Recall@K，并按权限、语言、长度切片。</li><li>结果异常时检查切分单位、空文本、归一化、模型升级和元数据过滤。</li></ol><h2 id="练习与完成标准" tabindex="-1">练习与完成标准 <a class="header-anchor" href="#练习与完成标准" aria-label="Permalink to &quot;练习与完成标准&quot;">​</a></h2><p>为 10 个短文档实现一个暴力余弦检索。验收：拒绝零向量；返回原文、来源和分数；对 5 个标注查询计算 Recall@3；证明混用不同维度向量会被显式拒绝。</p><h2 id="完整案例-带权限的内部文档检索" tabindex="-1">完整案例：带权限的内部文档检索 <a class="header-anchor" href="#完整案例-带权限的内部文档检索" aria-label="Permalink to &quot;完整案例：带权限的内部文档检索&quot;">​</a></h2><h3 id="输入" tabindex="-1">输入 <a class="header-anchor" href="#输入" aria-label="Permalink to &quot;输入&quot;">​</a></h3><ul><li>三篇文档：公开报销说明、财务专用审批规则、人事专用休假规则。</li><li>查询：“差旅报销需要谁审批？”</li><li>当前用户只有公开文档权限；标注相关集合只包含公开报销说明。</li><li>Embedding 模型和索引版本均为 <code>embed-v2</code>，向量维度一致。</li></ul><h3 id="逐步处理" tabindex="-1">逐步处理 <a class="header-anchor" href="#逐步处理" aria-label="Permalink to &quot;逐步处理&quot;">​</a></h3><ol><li>文档按标题与段落切分，每个 Chunk 保存 <code>document_id</code>、正文、权限、时间和模型版本。</li><li>查询使用同一规范化过程和模型生成向量。</li><li>在数据库查询中先强制 <code>visibility=public</code>，再按余弦相似度取前 5。</li><li>对候选执行关键词与语义混合排序，并保留原始分数。</li><li>返回原文和来源给生成模型；若没有达到评测确定的证据条件，返回无答案状态。</li></ol><h3 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h3><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;query_id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;q-17&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;embedding_model&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;embed-v2&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;metric&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;cosine_similarity&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;results&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    {</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;document_id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;travel-public&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;score&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.82</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;authorized&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>财务专用规则即使向量分数更高也不能进入候选或模型上下文。权限过滤是授权规则，不是相关性优化。</p><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ul><li>人工构造相同向量，确认数据库分数相等且排序稳定。</li><li>以 20 个标注查询计算 Recall@5，并分别报告公开与受限文档切片。</li><li>检查结果中的模型版本、维度、距离名称和排序方向。</li><li>删除文档时同步删除原文、向量与派生索引项，并用查询确认不可召回。</li></ul><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>若升级到 <code>embed-v3</code> 后只重算查询向量，分数没有可比较含义。应建立新索引、重算全部文档、在同一查询集比较 Recall@K，再通过版本切换完成迁移；不能在同一索引静默混用。</p><h2 id="边界检查矩阵" tabindex="-1">边界检查矩阵 <a class="header-anchor" href="#边界检查矩阵" aria-label="Permalink to &quot;边界检查矩阵&quot;">​</a></h2><ol><li>零向量：余弦分母为零时必须拒绝或定义显式策略。</li><li>维度：写入和查询前校验长度，避免运行时数据库错误。</li><li>模型：记录完整模型与预处理版本，升级时重建索引。</li><li>度量：确认数据库返回 similarity 还是 distance 以及排序方向。</li><li>归一化：只有明确做 L2 归一化时，点积才等于余弦。</li><li>切分：Chunk 太短丢上下文，太长会混合多个主题。</li><li>权限：过滤在检索信任边界执行，不依赖生成模型忽略。</li><li>新鲜度：保留更新时间并定义过期文档处理。</li><li>删除：原文、向量、缓存和派生索引需要可追踪删除。</li><li>混合检索：关键词与向量分数需校准，不能直接假设同一量纲。</li><li>Rerank：只重排候选，无法召回初始阶段遗漏的文档。</li><li>验证：用真实标注查询计算 Recall@K 和最终任务指标。</li></ol><h2 id="相似度阈值与-top-k-的区别" tabindex="-1">相似度阈值与 Top-K 的区别 <a class="header-anchor" href="#相似度阈值与-top-k-的区别" aria-label="Permalink to &quot;相似度阈值与 Top-K 的区别&quot;">​</a></h2><p>Top-K 始终尝试返回排名最靠前的 K 个候选，即使所有候选都很差；阈值则拒绝未达到条件的候选，但阈值的数值只对指定模型、预处理、距离实现和数据分布有意义。不能从另一个模型复制 <code>0.8</code> 之类的阈值。应在标注查询上画出不同阈值的召回率、精确率与无结果比例，并根据漏召回和误召回损失选择。</p><p>近似最近邻索引还包含构建参数与查询参数。提高搜索深度通常改善召回但增加延迟；量化可减少内存但会改变距离精度。参数名称由数据库实现定义，报告必须同时给出索引类型、构建版本、查询参数、数据规模、P95 延迟和 Recall@K。仅凭一条查询“看起来正确”不能证明索引配置合格。</p><p>若业务需要引用，结果对象必须保留原始文档 ID、Chunk 边界、版本和可访问原文。向量本身不能还原可审计来源，也不能作为删除、授权或事实支持的唯一记录。</p><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://developers.google.com/machine-learning/crash-course/embeddings" target="_blank" rel="noreferrer">Google ML Crash Course：Embeddings</a>（访问日期：2026-07-17）</li><li><a href="https://www.tensorflow.org/text/guide/word_embeddings" target="_blank" rel="noreferrer">TensorFlow：Vector Embeddings</a>（访问日期：2026-07-17）</li><li><a href="https://docs.scipy.org/doc/scipy/reference/generated/scipy.spatial.distance.cosine.html" target="_blank" rel="noreferrer">SciPy：Cosine Distance</a>（访问日期：2026-07-17）</li></ul>`,47)])])}const u=i(t,[["render",n]]);export{k as __pageData,u as default};
